CREATE TABLE "CommissionEntry" ("id" TEXT NOT NULL PRIMARY KEY,"paymentId" TEXT NOT NULL,"saleId" TEXT NOT NULL,"type" TEXT NOT NULL,"baseCents" INTEGER NOT NULL,"percentageBps" INTEGER NOT NULL,"amountCents" INTEGER NOT NULL,"status" TEXT NOT NULL DEFAULT 'CONFIRMED',"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "CommissionEntry_paymentId_fkey" FOREIGN KEY ("paymentId") REFERENCES "Payment"("id") ON DELETE CASCADE,CONSTRAINT "CommissionEntry_saleId_fkey" FOREIGN KEY ("saleId") REFERENCES "Sale"("id") ON DELETE CASCADE);
